				ss1 <= 0;
				ss2 <= 1;
				ss3 <= 1;
			end

		`SPI_SELECT2 :
			begin
				// Select SPI Slave #2
				ss1 <= 1;
				ss2 <= 0;
				ss3 <= 1;
			end

		`SPI_SELECT3 :
			begin
				// Select SPI Slave #3
				ss1 <= 1;
				ss2 <= 1;
				ss3 <= 0;
			end

		`SPI_SET_MOSI :
			begin
				// Bit-banged SPI; Set MOSI=1
				fg_mosi <= 1;
			end

		`SPI_CLR_MOSI :
			begin
				// Bit-banged SPI; Set MOSI=0
				fg_mosi <= 0;
			end

		`SPI_SET_SCLK :
			begin
				// Bit-banged SPI; Set SCLK=1
				fg_sclk <= 1;
			end

		`SPI_CLR_SCLK :
			begin
				// Bit-banged SPI; Set SCLK=0
