			// Shifted
			// Shift has completed; reset registers
			begin
				spi_xfer_running <= 0;	// Signal transfer ended
				bg_mosi <= 1;				// Reset MOSI
				spi_state <= `STATE_5;	// Next state is Epilogue
			end

