	output 				SDRAM_nWE,     // write enable
	output 				SDRAM_nRAS,    // row address select
	output 				SDRAM_nCAS,    // columns address select
	output 				SDRAM_CLK,

	// cpu/chipset interface
	input 		 		init,			   // init signal after FPGA config to initialize RAM
	input 		 		clk,			   // sdram is accessed at up to 128MHz
	input					sync,  		   // reference clock to sync to

	input      [15:0] din,			   // data input from chipset/cpu
	output reg [15:0] dout,			   // data output to chipset/cpu
	input      [23:0] addr,          // 25 bit word address
	input       [1:0] ds,            // data strobe for hi/low byte
	input 		 		oe,            // cpu/chipset requests read
	input 		 		we             // cpu/chipset requests write
);

// no burst configured
localparam RASCAS_DELAY   = 3'd2;   // tRCD>=20ns -> 2 cycles@64MHz
localparam BURST_LENGTH   = 3'b000; // 000=none, 001=2, 010=4, 011=8
localparam ACCESS_TYPE    = 1'b0;   // 0=sequential, 1=interleaved
localparam CAS_LATENCY    = 3'd2;   // 2/3 allowed
localparam OP_MODE        = 2'b00;  // only 00 (standard operation) allowed
localparam NO_WRITE_BURST = 1'b1;   // 0= write burst enabled, 1=only single access write

localparam MODE = { 3'b000, NO_WRITE_BURST, OP_MODE, CAS_LATENCY, ACCESS_TYPE, BURST_LENGTH}; 

// ---------------------------------------------------------------------
// ------------------------ cycle state machine ------------------------
// ---------------------------------------------------------------------

localparam STATE_IDLE      = 3'd0;   // first state in cycle
localparam STATE_CMD_START = 3'd1;   // state in which a new command can be started
localparam STATE_CMD_CONT  = STATE_CMD_START + RASCAS_DELAY;       // 4 command can be continued
localparam STATE_DOUT      = STATE_CMD_CONT  + CAS_LATENCY + 1'd1;
localparam STATE_LAST      = 3'd7;   // last state in cycle

reg [2:0] q /* synthesis noprune */;
always @(posedge clk) if((q != STATE_LAST) || sync) q <= q + 1'd1;

// ---------------------------------------------------------------------
// --------------------------- startup/reset ---------------------------
// ---------------------------------------------------------------------

// wait 1ms (32 clkref cycles) after FPGA config is done before going
// into normal operation. Initialize the ram in the last 16 reset cycles (cycles 15-0)
reg [4:0] reset;
always @(posedge clk) begin
	if(init)	reset <= 5'h1f;
	else if((q == STATE_CMD_START) && (reset != 0)) // cannot use 0/7 values if clkref is not clk/8
		reset <= reset - 5'd1;
end

// ---------------------------------------------------------------------
// ------------------ generate ram control signals ---------------------
// ---------------------------------------------------------------------

// all possible commands
localparam CMD_NOP             = 3'b111;
localparam CMD_ACTIVE          = 3'b011;
localparam CMD_READ            = 3'b101;
localparam CMD_WRITE           = 3'b100;
localparam CMD_BURST_TERMINATE = 3'b110;
localparam CMD_PRECHARGE       = 3'b010;
localparam CMD_AUTO_REFRESH    = 3'b001;
localparam CMD_LOAD_MODE       = 3'b000;

reg [2:0] sd_cmd;   // current command sent to sd ram

// drive control signals according to current command
assign SDRAM_nCS  = 0;
assign SDRAM_nRAS = sd_cmd[2];
assign SDRAM_nCAS = sd_cmd[1];
assign SDRAM_nWE  = sd_cmd[0];
assign {SDRAM_DQMH,SDRAM_DQML} = SDRAM_A[12:11];


always @(posedge clk) begin
	reg [1:0] dqm;
	reg [1:0] state;

	sd_cmd <= CMD_NOP;
	SDRAM_DQ <= 16'bZ;

	if(reset != 0) begin
		SDRAM_BA <= 2'b00;

		if(reset == 13) SDRAM_A <= 13'b0010000000000;
		else   			 SDRAM_A <= MODE;

		if(q == STATE_CMD_START) begin
			if(reset == 13)  sd_cmd <= CMD_PRECHARGE;
			if(reset ==  2)  sd_cmd <= CMD_LOAD_MODE;
		end
	end else begin

		if(q == STATE_IDLE) state <= {we,oe};
		else if(q <= STATE_CMD_START) begin	
			sd_cmd <= CMD_AUTO_REFRESH;
			if(state) begin
				sd_cmd <= CMD_ACTIVE;
				SDRAM_A <= addr[20:8];
				SDRAM_BA <= addr[22:21];
				dqm <= state[1] ? ~ds : 2'b00;
			end
		end
		else if(q == STATE_CMD_CONT) begin
			if(state) SDRAM_A <= { dqm, 2'b10, addr[23], addr[7:0]};
			if(state[1]) begin
				sd_cmd <= CMD_WRITE;
				SDRAM_DQ <= din;
			end
			else if(state[0]) sd_cmd <= CMD_READ;
		end
		else if(q == STATE_DOUT) begin
			if(state[0]) dout <= SDRAM_DQ;
		end
	end
end

altddio_out
#(
	.extend_oe_disable("OFF"),
	.intended_device_family("Cyclone V"),
	.invert_output("OFF"),
	.lpm_hint("UNUSED"),
	.lpm_type("altddio_out"),
	.oe_reg("UNREGISTERED"),
	.power_up_high("OFF"),
	.width(1)
)
sdramclk_ddr
(
	.datain_h(1'b0),
	.datain_l(1'b1),
	.outclock(clk),
	.dataout(SDRAM_CLK),
	.aclr(1'b0),
	.aset(1'b0),
	.oe(1'b1),
	.outclocken(1'b1),
	.sclr(1'b0),
	.sset(1'b0)
);

endmodule

